class GsonToJsonTest {

  private Gson gson;

  @BeforeEach
  void setUp() {
    gson = new Gson();
  }

  @Test
  void toJson_withNullObject_returnsJsonNull() {
    String json = gson.toJson(null, Object.class);
    assertEquals("null", json);
  }

  @Test
  void toJson_withPrimitiveInteger_returnsJsonNumber() {
    Integer src = 123;
    String json = gson.toJson(src, Integer.class);
    assertEquals("123", json);
  }

  @Test
  void toJson_withString_returnsJsonString() {
    String src = "test";
    String json = gson.toJson(src, String.class);
    assertEquals("\"test\"", json);
  }

  @Test
  void toJson_withCustomObject_returnsJsonObject() {
    class Custom {
      int x = 10;
      String y = "foo";
    }
    Custom src = new Custom();
    String json = gson.toJson(src, Custom.class);
    assertTrue(json.contains("\"x\":10"));
    assertTrue(json.contains("\"y\":\"foo\""));
  }

  @Test
  void toJson_invokesPrivateToJsonWithWriter() throws Exception {
    String src = "abc";
    Type type = String.class;

    Method toJsonMethod = Gson.class.getDeclaredMethod("toJson", Object.class, Type.class, java.io.Appendable.class);
    toJsonMethod.setAccessible(true);

    StringWriter writer = new StringWriter();
    toJsonMethod.invoke(gson, src, type, writer);

    assertEquals("\"abc\"", writer.toString());
  }
}
